mapper.select:
select s.*, c.course_name, u.real_name as teacher_name, t.term_name, cl.name as class_name from course_schedule s left join course_info c on s.course_id = c.id left join sys_user u on s.teacher_id = u.id left join academic_term t on s.term_id = t.id left join class_info cl on s.class_id = cl.id
and c.course_name like concat('%', #{courseName}, '%')
and s.teacher_id = #{teacherId}
and s.term_id = #{termId}
and s.class_id = #{classId}
and s.status = #{status}
order by s.id desc

mapper.update:
update course_schedule
course_id = #{courseId}, term_id = #{termId}, teacher_id = #{teacherId}, class_id = #{classId}, classroom = #{classroom}, week_day = #{weekDay}, start_section = #{startSection}, end_section = #{endSection}, max_student_count = #{maxStudentCount}, selected_count = #{selectedCount}, status = #{status},
where id = #{id}
